class MinStack:

    def __init__(self):
        self.stack = []
        self.sortlist = []


    def push(self, val: int) -> None:
        self.stack.append(val)
        if self.sortlist:
            val = min(self.sortlist[-1],val)
        self.sortlist.append(val)


    def pop(self) -> None:
        self.stack.pop()
        self.sortlist.pop()



    def top(self) -> int:
        return self.stack[-1]


    def getMin(self) -> int:
        return self.sortlist[-1]



